// ─── Utility helpers ───────────────────────────────────────────────
function parseValue(v) {
  const n = parseFloat(String(v).replace(/[^0-9.-]/g, ''));
  return isNaN(n) ? null : n;
}

function parseDate(dateStr, timeStr) {
  try {
    const combined = `${dateStr} ${timeStr || '00:00'}`;
    const d = new Date(combined);
    return isNaN(d.getTime()) ? new Date(0) : d;
  } catch { return new Date(0); }
}

// ─── Raw rows ──────────────────────────────────────────────────────
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No data found in the Google Sheet.');
}

// ─── Normalise & sort ──────────────────────────────────────────────
const rows = items
  .map(item => ({
    time:        String(item.json.TIME        || item.json.time        || '').trim(),
    date:        String(item.json.DATE        || item.json.date        || '').trim(),
    description: String(item.json.DESCRIPTION || item.json.description || 'Unknown').trim(),
    rawValue:    String(item.json.VALUE       || item.json.value       || '').trim(),
    numericValue: parseValue(item.json.VALUE  || item.json.value       || '')
  }))
  .filter(r => r.date !== '' && r.description !== '')
  .map(r => ({ ...r, timestamp: parseDate(r.date, r.time) }))
  .sort((a, b) => b.timestamp - a.timestamp);          // newest first

if (rows.length === 0) throw new Error('No valid rows after normalisation.');

// ─── Recency window ────────────────────────────────────────────────
const RECENT_N   = Math.min(20, rows.length);
const recentRows = rows.slice(0, RECENT_N);

// ─── Group by metric ──────────────────────────────────────────────
const metricMap = {};
for (const r of rows) {
  const key = r.description.toLowerCase();
  if (!metricMap[key]) metricMap[key] = { label: r.description, values: [] };
  if (r.numericValue !== null) metricMap[key].values.push(r.numericValue);
}

// ─── Known reference ranges ────────────────────────────────────────
const RANGES = {
  'blood pressure':     { min: 90,  max: 120, unit: 'mmHg' },
  'heart rate':         { min: 60,  max: 100, unit: 'bpm'  },
  'pulse':              { min: 60,  max: 100, unit: 'bpm'  },
  'temperature':        { min: 36.1,max: 37.2,unit: '°C'   },
  'body temperature':   { min: 36.1,max: 37.2,unit: '°C'   },
  'oxygen saturation':  { min: 95,  max: 100, unit: '%'    },
  'spo2':               { min: 95,  max: 100, unit: '%'    },
  'glucose':            { min: 70,  max: 140, unit: 'mg/dL'},
  'blood glucose':      { min: 70,  max: 140, unit: 'mg/dL'},
  'weight':             { min: 0,   max: 9999,unit: 'kg'   },
  'bmi':                { min: 18.5,max: 24.9,unit: ''     },
  'steps':              { min: 0,   max: 99999,unit: 'steps'},
  'sleep':              { min: 6,   max: 9,   unit: 'hrs'  },
  'sleep duration':     { min: 6,   max: 9,   unit: 'hrs'  },
  'respiratory rate':   { min: 12,  max: 20,  unit: 'brpm' },
  'systolic':           { min: 90,  max: 120, unit: 'mmHg' },
  'diastolic':          { min: 60,  max: 80,  unit: 'mmHg' }
};

function getRange(label) {
  const key = label.toLowerCase();
  return RANGES[key] || null;
}

function classifyValue(val, range) {
  if (!range || val === null) return 'normal';
  if (val < range.min) return 'low';
  if (val > range.max) return 'high';
  return 'normal';
}

// ─── Summary stats per metric ─────────────────────────────────────
const metricStats = [];
for (const [, m] of Object.entries(metricMap)) {
  if (m.values.length === 0) continue;
  const sorted = [...m.values].sort((a, b) => a - b);
  const avg    = m.values.reduce((s, v) => s + v, 0) / m.values.length;
  const range  = getRange(m.label);
  const status = classifyValue(avg, range);
  metricStats.push({
    label:   m.label,
    count:   m.values.length,
    avg:     Math.round(avg * 10) / 10,
    min:     sorted[0],
    max:     sorted[sorted.length - 1],
    latest:  m.values[0],            // values already newest-first
    unit:    range?.unit || '',
    refMin:  range?.min ?? null,
    refMax:  range?.max ?? null,
    status
  });
}

// ─── Anomaly detection ────────────────────────────────────────────
const anomalies = [];
for (const r of recentRows) {
  if (r.numericValue === null) continue;
  const range  = getRange(r.description);
  const status = classifyValue(r.numericValue, range);
  if (status !== 'normal') {
    anomalies.push({
      date:        r.date,
      time:        r.time,
      description: r.description,
      value:       r.rawValue,
      status,
      refMin:      range?.min,
      refMax:      range?.max,
      unit:        range?.unit || ''
    });
  }
}

// ─── Trend analysis ───────────────────────────────────────────────
const trends = [];
for (const [, m] of Object.entries(metricMap)) {
  if (m.values.length < 3) continue;
  const recent3  = m.values.slice(0, 3);
  const older3   = m.values.slice(-3);
  const recentAv = recent3.reduce((s,v) => s+v, 0) / recent3.length;
  const olderAv  = older3.reduce((s,v) => s+v, 0)  / older3.length;
  const change   = ((recentAv - olderAv) / (Math.abs(olderAv) || 1)) * 100;
  let direction  = 'stable';
  if (change > 5)  direction = 'increasing';
  if (change < -5) direction = 'decreasing';
  if (direction !== 'stable') {
    trends.push({
      label:     m.label,
      direction,
      changePct: Math.round(Math.abs(change)),
      recentAvg: Math.round(recentAv * 10) / 10
    });
  }
}

// ─── Summary for AI prompt ────────────────────────────────────────
const summaryText = metricStats
  .map(s => `${s.label}: latest=${s.latest}${s.unit}, avg=${s.avg}${s.unit}, min=${s.min}, max=${s.max}, status=${s.status}`)
  .join('\n');

const anomalySummary = anomalies.length
  ? anomalies.map(a => `${a.description} was ${a.status} (${a.value}) on ${a.date}`).join('; ')
  : 'No anomalies detected.';

const trendSummary = trends.length
  ? trends.map(t => `${t.label} is ${t.direction} by ~${t.changePct}%`).join('; ')
  : 'Metrics appear stable overall.';

const promptForAI = `You are a professional clinical health analyst.\n\nBelow is a summary of a patient's recent health log data.\n\nMETRIC SUMMARY:\n${summaryText}\n\nANOMALIES DETECTED:\n${anomalySummary}\n\nTREND ANALYSIS:\n${trendSummary}\n\nProvide a concise, professional health insights report (4–6 bullet points) covering:\n1. Overall health status\n2. Any concerning values or patterns\n3. Positive findings\n4. Actionable recommendations\n\nUse plain English suitable for a patient summary. Do NOT use markdown, headers, or asterisks in your output — return only plain bullet points starting with '•'.`;

return [{
  json: {
    recentRows,
    metricStats,
    anomalies,
    trends,
    totalRows:     rows.length,
    generatedAt:   new Date().toISOString(),
    promptForAI
  }
}];

const subject = $('Build HTML Dashboard').first().json.subject;
return [{
  json: {
    status: 'success',
    message: 'Health analytics report sent successfully.',
    emailSubject: subject,
    sentAt: new Date().toISOString()
  }
}];
